        const s_a = '1'.repeat(nums1[a]) + '0'.repeat(nums0[a]);
        const s_b = '1'.repeat(nums1[b]) + '0'.repeat(nums0[b]);

        // Compare s_a + s_b vs s_b + s_a lexicographically.
        const ab = s_a + s_b;
        const ba = s_b + s_a;

        if (ab > ba) return -1; // s_a should come first (smaller return value in standard sort)
        if (ab < ba) return 1;  // s_b should come first
