    // where $p_i$ is the sorted index, and $\text{shift}_i$ is the length of segments placed after $S_{p_i}$.

    // A simpler approach is to calculate the final binary string's value directly modulo MOD.
    // Since we are dealing with binary numbers, the base is 2.

    let currentLength = 0; // Total length of the concatenated string so far
    let finalResult = 0n;

