        } else if (nums0[i] > 0) {
            // Segment is all zeros, value is 0.
            segmentValue = 0n;
        }
        // Note: nums1[i] + nums0[i] > 0 is guaranteed.

        finalResult = (finalResult + segmentValue) % BigInt(MOD);

        currentLength += len;
    }

    return Number(finalResult);
